from pydantic import BaseModel, Field
from typing import List

class UnderwritingOutput(BaseModel):
    premium: float
    risk_score: float = Field(ge=0, le=1.0)
    explanation: str = Field(min_length=100)
    adverse_notice: str

@vex.guard("fcra_compliance")
def underwriting_validator(output: UnderwritingOutput) -> bool:
    prohibited_sources = ['credit_score', 'ml_model_unexplained', 'proxy_data']
    if any(source in output.explanation.lower() for source in prohibited_sources):
        vex.flag('fcra_violation', {'output': output.model_dump()})
        return False
    if 'protected class' in output.explanation or output.risk_score > 0.9:
        return False
    return True

underwriting_agent = Agent(
    output_type=UnderwritingOutput,
    result_validator=underwriting_validator
)

import re
from vex import Guardrail

pii_guardrail = Guardrail("pii_redaction", rules={
    'ssn': r'\b\d{3}-\d{2}-\d{4}\b',
    'medical_history': r'(diagnosis|condition|treatment|hospital)\s+[a-zA-Z]+',
    'full_name': r'\b[A-Z][a-z]+\s+[A-Z][a-z]+\b'
})

def policy_data_validator(result: dict) -> dict:
    cleaned = result.copy()
    for field in ['customer_data', 'claim_details']:
        if field in cleaned:
            for pattern_name, pattern in pii_guardrail.rules.items():
                cleaned[field] = re.sub(pattern, '[REDACTED]', str(cleaned[field]))
    vex.audit('pii_check', {'redacted_fields': len(pii_guardrail.rules)})
    return cleaned

policy_agent = Agent(
    tools=[customer_lookup, claims_history_tool],
    result_validator=policy_data_validator
